const item = $input.first().json;

const channels = Array.isArray(item.channels) ? item.channels.join(', ') : (item.channels || 'linkedin');
const contentType = item.content_type || 'post';
const feedback = item.revision_feedback || '';

let userPrompt = `Przygotuj ${contentType} na kanaly: ${channels}.

Material zrodlowy:
${item.raw_text}`;

if (feedback) {
  userPrompt += `\n\nPoprawki od uzytkownika (zastosuj je):\n${feedback}`;
}

const systemPrompt = `Jestes doswiadczonym copywriterem marketingowym. Tworzysz angazujace tresci na social media.

NAJWAZNIEJSZA ZASADA: ZAWSZE generuj gotowa tresc posta. NIGDY nie pytaj o dodatkowe informacje, nie pros o doprecyzowanie, nie zadawaj pytan. Pracuj z tym co dostales - nawet jesli material zrodlowy jest krotki lub ogolny, stworz z niego najlepszy mozliwy post.

Zasady:
- Pisz po polsku, chyba ze uzytkownik wskaze inaczej
- Dostosuj ton i dlugosc do kanalu (LinkedIn = profesjonalny, max 3000 znakow; Facebook = luzniejszy; Instagram = krotki + hashtagi)
- Dodaj odpowiednie emoji i hashtagi jesli pasuja do kanalu
- Podaj TYLKO gotowa tresc posta - bez meta-komentarzy, bez "oto post", bez wyjasnien
- Jesli jest kilka kanalow, przygotuj osobna wersje dla kazdego, oddzielona naglowkiem kanalu`;

return [{ json: { systemPrompt, userPrompt, job_id: item.job_id } }];

const item = $input.first().json;
const jobId = $('Build Prompt').first().json.job_id;

return [{ json: {
  job_id: jobId,
  generated_text: item.text || item.output || JSON.stringify(item)
} }];

const item = $input.first().json;
const text = item.generated_text || '';

const lines = text.split('\n').filter(l => l.trim());
let title = lines[0] || 'Career Guide';
let subtitle = lines.slice(1, 3).join(' ').substring(0, 120);

title = title.replace(/^#+\s*/, '').replace(/\*\*/g, '').substring(0, 80);
subtitle = subtitle.replace(/\*\*/g, '').replace(/^[-•]\s*/, '');

const esc = s => s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

const css = `@import url("https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap");:root{--cg-brand-primary:#4d96d9;--cg-brand-accent:#89c6eb;--cg-text-default:#1a1e32;--cg-text-muted:#667797;--cg-surface-page:#fcfcfe;--cg-matcher-cyan:#00acc1;--cg-matcher-purple:#8e44ad;--cg-matcher-pink:#d81b60}.cg-root.cg-dark{--cg-brand-primary:#8cb2e6;--cg-brand-accent:#a7dbff;--cg-text-default:#fbfbfd;--cg-text-muted:#a5afc8;--cg-surface-page:#161b2b}*,*::before,*::after{box-sizing:border-box}html,body{margin:0;padding:0;width:100%;height:100%;-webkit-font-smoothing:antialiased}body{font-family:"Inter",system-ui,sans-serif;font-size:18px;line-height:1.45;color:var(--cg-text-default);background:var(--cg-surface-page)}.cg-root{width:100%;height:100%;min-height:100%;color:var(--cg-text-default);background:var(--cg-surface-page)}.cg-layout{display:flex;flex-direction:column;align-items:center;justify-content:center;width:100%;height:100%;padding:48px 56px;max-width:1200px;margin:0 auto;text-align:center}.cg-kicker{font-size:14px;font-weight:600;letter-spacing:0.12em;text-transform:uppercase;color:var(--cg-brand-primary);margin:0 0 12px}.cg-title{font-size:44px;font-weight:700;line-height:1.15;color:var(--cg-text-default);margin:0 0 16px}.cg-subtitle{font-size:22px;font-weight:500;line-height:1.35;color:var(--cg-text-muted);margin:0;max-width:920px}.cg-rule{height:4px;width:120px;border-radius:999px;background:linear-gradient(90deg,var(--cg-matcher-cyan),var(--cg-matcher-purple),var(--cg-matcher-pink));margin:24px auto}`;

const html = `<div class="cg-root cg-dark"><div class="cg-layout"><p class="cg-kicker">Career Guide</p><h1 class="cg-title">${esc(title)}</h1><p class="cg-subtitle">${esc(subtitle)}</p><div class="cg-rule"></div></div></div>`;

return [{ json: {
  ...item,
  image_html: html,
  image_css: css
} }];

const imgItem = $input.first();
const prevData = $('Build Image HTML').first().json;

return [{ json: {
  job_id: prevData.job_id,
  generated_text: prevData.generated_text
}, binary: imgItem.binary }];

